    my ($pdf) = @_;
    my $meta = $pdf->getMetadata();
    my %metadata = %$meta;

    my $author = defined($metadata{'dc:creator'}) ? $metadata{'dc:creator'} : 'Unknown';
    my $date = defined($metadata{'dc:date'}) ? $metadata{'dc:date'} : 'Unknown';

