    my ($pdf, $page_num) = @_;
    my $page = $pdf->getPageContent($page_num);
    # Assuming we are looking for simple table patterns, this is a simplistic approach
    my @tables = $page =~ /Table\s+([\d\s]+)/g;

    if (@tables) {
        print "Tables found:\n";
        foreach my $table (@tables) {
